#!/bin/bash
# This file was generated by Cursor AI on 2025-01-16.
#
# Script to process a list of files using c2po.py with template.cmd in parallel
# Usage: ./benchmark.sh <input_file_list> <output_csv> <timeout> <memout> <num_jobs> [c2po_path]
#
# Arguments:
#   input_file_list: File containing list of files to process (one per line)
#   output_csv: Output CSV file to write results to
#   timeout: Timeout value for optimize_eqsat in seconds (required)
#   memout: Memory limit for optimize_eqsat in MB (required)
#   num_jobs: Number of parallel jobs to run (required)
#   c2po_path: Path to c2po.py (default: compiler/c2po.py)

set -euo pipefail

# Get script directory
SCRIPT_DIR="$(cd "$(dirname "${BASH_SOURCE[0]}")" && pwd)"
PROJECT_ROOT="$(cd "$SCRIPT_DIR/../../.." && pwd)"

# Parse arguments
if [ $# -lt 5 ]; then
    echo "Usage: $0 <input_file_list> <output_csv> <timeout> <memout> <num_jobs> [c2po_path]" >&2
    exit 1
fi

INPUT_FILE="$1"
OUTPUT_CSV="$2"
TIMEOUT="$3"
MEMOUT="$4"
NUM_JOBS="$5"
C2PO_PATH="${6:-$PROJECT_ROOT/compiler/c2po.py}"

# Validate memout is a positive integer
if ! [[ "$MEMOUT" =~ ^[1-9][0-9]*$ ]]; then
    echo "Error: memout must be a positive integer" >&2
    exit 1
fi

# Validate num_jobs is a positive integer
if ! [[ "$NUM_JOBS" =~ ^[1-9][0-9]*$ ]]; then
    echo "Error: num_jobs must be a positive integer" >&2
    exit 1
fi

# Convert to absolute paths
INPUT_FILE="$(cd "$(dirname "$INPUT_FILE")" && pwd)/$(basename "$INPUT_FILE")"
OUTPUT_CSV="$(cd "$(dirname "$OUTPUT_CSV")" && pwd)/$(basename "$OUTPUT_CSV")"
C2PO_PATH="$(cd "$(dirname "$C2PO_PATH")" && pwd)/$(basename "$C2PO_PATH")"

# Check if input file exists
if [ ! -f "$INPUT_FILE" ]; then
    echo "Error: Input file '$INPUT_FILE' does not exist" >&2
    exit 1
fi

# Check if c2po.py exists
if [ ! -f "$C2PO_PATH" ]; then
    echo "Error: c2po.py file '$C2PO_PATH' does not exist" >&2
    exit 1
fi

# Check if GNU parallel is available
if ! command -v parallel &> /dev/null; then
    echo "Error: GNU parallel is not installed. Please install it first." >&2
    exit 1
fi

# Create temporary directory for template files
TEMPLATE_TMPDIR=$(mktemp -d)
trap "rm -rf $TEMPLATE_TMPDIR" EXIT

# Function to process a single file
process_file() {
    local input_file="$1"
    local timeout="$2"
    local memout="$3"
    local c2po_path="$4"
    local tmpdir="$5"
    
    # Get absolute path of input file
    local abs_input_file
    if [[ "$input_file" = /* ]]; then
        abs_input_file="$input_file"
    else
        abs_input_file="$(cd "$(dirname "$input_file")" && pwd)/$(basename "$input_file")"
    fi
    
    # Check if file exists
    if [ ! -f "$abs_input_file" ]; then
        echo "Error: File '$input_file' does not exist" >&2
        return 1
    fi
    
    # Validate tmpdir is set
    if [ -z "$tmpdir" ] || [ ! -d "$tmpdir" ]; then
        echo "Error: Invalid temporary directory: '$tmpdir'" >&2
        return 1
    fi
    
    # Determine file type and create appropriate template
    local basename_file=$(basename "$abs_input_file")
    local temp_template="$tmpdir/template_${BASHPID}_$(basename "$abs_input_file" | tr '/' '_').cmd"
    
    # Convert to absolute path
    temp_template="$(cd "$(dirname "$temp_template")" && pwd)/$(basename "$temp_template")"
    
    # Generate template content with timeout
    local template_content
    template_content="type_check
desugar
compute_atomics

push
push
push

optimize_cse
compute_scq_sizes
print_stats \"%F,%S,\"

optimize_eqsat --egglog-max-time $timeout --egglog-max-memory $memout --gurobi-max-time $timeout --gurobi-max-memory $memout --extraction-method optimal
optimize_cse
compute_scq_sizes
print_stats \"%S,%et,%es,%ge,%gt,%gs,%cr,\"

pop
optimize_eqsat --egglog-max-time $timeout --egglog-max-memory $memout --gurobi-max-time $timeout --gurobi-max-memory $memout --no-associative --extraction-method optimal
optimize_cse
compute_scq_sizes
print_stats \"%S,%et,%es,%ge,%gt,%gs,%cr,\"

pop
optimize_eqsat --egglog-max-time $timeout --egglog-max-memory $memout --gurobi-max-time $timeout --gurobi-max-memory $memout --no-commutative --extraction-method optimal
optimize_cse
compute_scq_sizes 
print_stats \"%S,%et,%es,%ge,%gt,%gs,%cr,\"

pop
optimize_eqsat --egglog-max-time $timeout --egglog-max-memory $memout --gurobi-max-time $timeout --gurobi-max-memory $memout --no-associative --no-commutative --extraction-method optimal
optimize_cse
compute_scq_sizes
print_stats \"%S,%et,%es%ge,%gt,%gs,%cr,\n\""
    
    # Generate template by prepending the appropriate command(s) to the template content
    if [[ "$basename_file" == *.c2po ]]; then
        # For .c2po files, prepend enable_booleanizer and parse_c2po
        {
            echo "enable_booleanizer"
            echo "parse_c2po $abs_input_file"
            echo ""
            echo "$template_content"
        } > "$temp_template"
    elif [[ "$basename_file" == *.mltl ]]; then
        # For .mltl files, prepend parse_mltl
        {
            echo "parse_mltl $abs_input_file"
            echo ""
            echo "$template_content"
        } > "$temp_template"
    else
        echo "Error: File '$input_file' must have .c2po or .mltl extension" >&2
        return 1
    fi
    
    # Run c2po.py and capture output
    # Change to compiler directory so Python can find the c2po module
    local compiler_dir="$(dirname "$c2po_path")"
    cd "$compiler_dir"
    
    # Run c2po and capture stdout (CSV output from print_stats)
    # Redirect stderr to /dev/null to suppress error messages during parallel execution
    # Errors will be visible in the progress output
    python3 "$(basename "$c2po_path")" -s "$temp_template" 2>/dev/null || {
        echo "ERROR,$input_file,Processing failed" >&2
        # Also output to stdout so it appears in CSV (as an error line)
        echo "ERROR,$input_file,Processing failed"
        return 1
    }
}

# Export function and variables for parallel
export -f process_file
export C2PO_PATH TEMPLATE_TMPDIR TIMEOUT MEMOUT

echo "# filename,orig_scq,full_scq,full_time,full_status,no_associative_scq,no_associative_time,no_associative_status,no_commutative_scq,no_commutative_time,no_commutative_status,no_associative_no_commutative_scq,no_associative_no_commutative_time,no_associative_no_commutative_status" > "$OUTPUT_CSV"

# Process files in parallel with progress bar
# Use --progress to show progress bar
# Use --line-buffer to show output as it arrives
# Use --jobs to limit number of parallel jobs
# Filter out empty lines and whitespace-only lines
# Collect all outputs to CSV file
grep -v '^[[:space:]]*$' "$INPUT_FILE" | parallel \
    --progress \
    --bar \
    --line-buffer \
    --jobs "$NUM_JOBS" \
    process_file {} "$TIMEOUT" "$MEMOUT" "$C2PO_PATH" "$TEMPLATE_TMPDIR" >> "$OUTPUT_CSV"

echo "Processing complete. Results saved to: $OUTPUT_CSV"
